const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  steps: QuoteStep[];
}

const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_PREMIUM = 60;

const sumBasePremiums = (items: Item[]): number => {
  const components: Item[] = [];
  const mainItems: Item[] = [];
  for (const item of items) {
    (COMPONENT_TYPES.has(item.type) ? components : mainItems).push(item);
  }
  const mainTotal = mainItems.reduce((total, item) => total + basePremiumFor(item), 0);
  // Group components by type
  const componentsByType = new Map<string, number>();
  for (const c of components) {
    componentsByType.set(c.type, (componentsByType.get(c.type) ?? 0) + 1);
  }
  let componentTotal = 0;
  for (const [, count] of componentsByType) {
    componentTotal += count === 3 ? BLOCK_PREMIUM : count * 25;
  }
  return mainTotal + componentTotal;
};

const quoteStep = (step: QuoteStep) => ({
  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
});

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  return { results: scenario.steps.map(quoteStep) };
};

